package com.tpverp.backend.document;
import static org.assertj.core.api.Assertions.*;import static org.mockito.ArgumentMatchers.*;import static org.mockito.Mockito.*;
import java.math.BigDecimal;import java.time.*;import java.util.*;import org.junit.jupiter.api.Test;
class PosCardCheckoutCoordinatorTest {
 @Test void atomicWinnerOwnsTheOnlyGatewayAttempt(){var repo=mock(PosCardCheckoutRepository.class);var now=Instant.parse("2026-07-11T10:00:00Z");var clock=Clock.fixed(now,ZoneOffset.UTC);var id=UUID.randomUUID();var terminal=UUID.randomUUID();var owner=UUID.randomUUID();var c=PosCardCheckout.reserve(id,terminal,"a".repeat(64),"snapshot",BigDecimal.ONE,owner,now,now.plusSeconds(30));when(repo.reserve(any(),any(),any(),any(),any(),any(),any(),any())).thenReturn(1);when(repo.findById(id)).thenReturn(Optional.of(c));var r=new PosCardCheckoutCoordinator(repo,clock).reserve(id,terminal,"a".repeat(64),"snapshot",BigDecimal.ONE,owner);assertThat(r.acquired()).isTrue();verify(repo,times(1)).reserve(any(),any(),any(),any(),any(),any(),any(),any());}
 @Test void sameIdWithDifferentHashIsConflictWithoutSecondReservation(){var repo=mock(PosCardCheckoutRepository.class);var now=Instant.now();var id=UUID.randomUUID();var terminal=UUID.randomUUID();var c=PosCardCheckout.reserve(id,terminal,"a".repeat(64),"snapshot",BigDecimal.ONE,UUID.randomUUID(),now,now.plusSeconds(30));when(repo.reserve(any(),any(),any(),any(),any(),any(),any(),any())).thenReturn(0);when(repo.findById(id)).thenReturn(Optional.of(c));assertThatThrownBy(()->new PosCardCheckoutCoordinator(repo,Clock.systemUTC()).reserve(id,terminal,"b".repeat(64),"snapshot",BigDecimal.ONE,UUID.randomUUID())).isInstanceOf(IllegalStateException.class).hasMessageContaining("otra venta");}
 @Test void expiredPendingBecomesSafeUncertainErrorAndIsNeverRecharged(){var repo=mock(PosCardCheckoutRepository.class);var now=Instant.parse("2026-07-11T10:00:00Z");var id=UUID.randomUUID();var terminal=UUID.randomUUID();var c=PosCardCheckout.reserve(id,terminal,"a".repeat(64),"snapshot",BigDecimal.ONE,UUID.randomUUID(),now.minusSeconds(60),now.minusSeconds(30));when(repo.reserve(any(),any(),any(),any(),any(),any(),any(),any())).thenReturn(0);when(repo.findById(id)).thenReturn(Optional.of(c));when(repo.save(any())).thenAnswer(i->i.getArgument(0));var r=new PosCardCheckoutCoordinator(repo,Clock.fixed(now,ZoneOffset.UTC)).reserve(id,terminal,"a".repeat(64),"snapshot",BigDecimal.ONE,UUID.randomUUID());assertThat(r.checkout().getStatus()).isEqualTo(com.tpverp.backend.terminal.PaymentTerminalOperationStatus.ERROR);assertThat(r.checkout().toResult().message()).contains("incierto");}
}
